import{_ as e,o as n,c as a,ai as i}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse(`{"title":"Scripts & Automation","description":"The four automation scripts that power Prism's autonomous execution and installation.","frontmatter":{"title":"Scripts & Automation","description":"The four automation scripts that power Prism's autonomous execution and installation.","outline":[2,3]},"headers":[],"relativePath":"plugin/scripts.md","filePath":"plugin/scripts.md","lastUpdated":0}`),t={name:"plugin/scripts.md"};function r(l,s,p,o,c,d){return n(),a("div",null,[...s[0]||(s[0]=[i(`<h1 id="scripts-automation" tabindex="-1">Scripts &amp; Automation <a class="header-anchor" href="#scripts-automation" aria-label="Permalink to “Scripts &amp; Automation”">​</a></h1><h2 id="scripts-spectrum-sh-312-lines" tabindex="-1"><code>scripts/spectrum.sh</code> (312 lines) <a class="header-anchor" href="#scripts-spectrum-sh-312-lines" aria-label="Permalink to “scripts/spectrum.sh (312 lines)”">​</a></h2><p>The Spectrum iterative executor — the main autonomous execution loop that spawns fresh Claude Code sessions per story.</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  spectrum.sh Loop                                    │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  1. Load stories.json                                │</span></span>
<span class="line"><span>│  2. Count remaining stories                          │</span></span>
<span class="line"><span>│  3. If 0 remaining → EXIT SUCCESS                    │</span></span>
<span class="line"><span>│  4. If max iterations → EXIT LIMIT                   │</span></span>
<span class="line"><span>│  5. Spawn: claude --dangerously-skip-permissions     │</span></span>
<span class="line"><span>│            --print &quot;/prism-spectrum&quot;                  │</span></span>
<span class="line"><span>│  6. Parse signal from output:                        │</span></span>
<span class="line"><span>│     • &lt;promise&gt;COMPLETE&lt;/promise&gt; → check remaining  │</span></span>
<span class="line"><span>│     • &lt;spectrum-continue&gt; → pause, next iteration    │</span></span>
<span class="line"><span>│     • &lt;spectrum-retry reason=&quot;...&quot;&gt; → increment err  │</span></span>
<span class="line"><span>│     • &lt;spectrum-blocked reason=&quot;...&quot;&gt; → skip story   │</span></span>
<span class="line"><span>│     • &lt;spectrum-error reason=&quot;...&quot;&gt; → stop           │</span></span>
<span class="line"><span>│  7. If 3+ consecutive errors → EXIT ERROR            │</span></span>
<span class="line"><span>│  8. Sleep $SPECTRUM_PAUSE seconds                     │</span></span>
<span class="line"><span>│  9. → Loop to step 2                                 │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p><strong>Environment variables:</strong></p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>SPECTRUM_MAX_ITERATIONS</code></td><td>50</td><td>Maximum iterations before stopping</td></tr><tr><td><code>SPECTRUM_VERBOSE</code></td><td>(unset)</td><td>Enable verbose output</td></tr><tr><td><code>SPECTRUM_PAUSE</code></td><td>2</td><td>Seconds between iterations</td></tr></tbody></table><p><strong>Prerequisites:</strong> <code>claude</code> CLI and <code>jq</code> must be installed.</p><h2 id="scripts-prism-cli-install-sh-280-lines" tabindex="-1"><code>scripts/prism-cli-install.sh</code> (280 lines) <a class="header-anchor" href="#scripts-prism-cli-install-sh-280-lines" aria-label="Permalink to “scripts/prism-cli-install.sh (280 lines)”">​</a></h2><p>Cross-platform bash installer for the prism-cli binary:</p><ul><li>Detects platform (darwin/linux/windows) and architecture (amd64/arm64)</li><li>Three methods: <code>auto</code> (try download, fall back to source), <code>download</code>, <code>source</code></li><li>Downloads from <code>github.com/TheDigitalGriot/prism-plugin/releases</code></li><li>Configures PATH in <code>~/.zshrc</code>, <code>~/.bashrc</code>, <code>~/.bash_profile</code>, and PowerShell <code>$PROFILE</code></li><li>Initializes <code>~/.prism/workspaces.json</code> registry</li></ul><h2 id="scripts-prism-cli-install-ps1-181-lines" tabindex="-1"><code>scripts/prism-cli-install.ps1</code> (181 lines) <a class="header-anchor" href="#scripts-prism-cli-install-ps1-181-lines" aria-label="Permalink to “scripts/prism-cli-install.ps1 (181 lines)”">​</a></h2><p>Native PowerShell installer for Windows:</p><ul><li>Downloads <code>prism-cli-windows-amd64.exe</code> from GitHub releases</li><li>Configures PATH in PowerShell <code>$PROFILE</code></li><li>Same auto/source/download method pattern as bash version</li></ul><h2 id="skills-prism-scripts-init-prism-py-174-lines" tabindex="-1"><code>skills/prism/scripts/init_prism.py</code> (174 lines) <a class="header-anchor" href="#skills-prism-scripts-init-prism-py-174-lines" aria-label="Permalink to “skills/prism/scripts/init_prism.py (174 lines)”">​</a></h2><p>Initializes the <code>.prism/</code> directory structure in any project:</p><ul><li>Creates 11 directories: <code>stories/</code>, <code>shared/{research,plans,validation,handoffs,prs,spectrum,ref,docs}</code>, <code>local/{ref,docs}</code></li><li>Adds <code>.prism/local/</code> to <code>.gitignore</code></li><li>Creates <code>README.md</code> in <code>.prism/shared/</code></li><li>Optionally adds Prism section to <code>CLAUDE.md</code></li></ul>`,16)])])}const h=e(t,[["render",r]]);export{u as __pageData,h as default};
